example.code:
interface Node { id: ID! }
interface Timestamped { createdAt: DateTime!  updatedAt: DateTime! }

type User implements Node & Timestamped {
  id: ID!
  email: String!
  name: String!
  createdAt: DateTime!
  updatedAt: DateTime!
  orders(first: Int, after: String, status: OrderStatus): OrderConnection!
}

type CreateUserPayload {
  user: User
  errors: [Error!]!
}

type Error {
  field: String
  message: String!
  code: String!
}

type Mutation {
  createUser(input: CreateUserInput!): CreateUserPayload!
}

import strawberry
from strawberry.types import Info
from typing import Optional
from uuid import UUID

@strawberry.type
class Query:
    @strawberry.field
    async def user(self, info: Info, id: strawberry.ID) -> Optional[User]:
        service = info.context.services.user
        return await service.get_by_id(UUID(id))

    @strawberry.field
    async def me(self, info: Info) -> Optional[User]:
        uid = info.context.current_user_id
        if not uid:
            return None
        return await info.context.services.user.get_by_id(uid)

@strawberry.type
class Mutation:
    @strawberry.mutation
    async def create_user(
        self, info: Info, input: CreateUserInput
    ) -> CreateUserPayload:
        try:
            user = await info.context.services.user.create(
                email=input.email, name=input.name
            )
            return CreateUserPayload(user=user, errors=[])
        except ValidationError as e:
            return CreateUserPayload(user=None, errors=[
                Error(field=err.field, message=err.message, code="VALIDATION")
                for err in e.errors
            ])

from strawberry.permission import BasePermission
from strawberry.types import Info

class IsAuthenticated(BasePermission):
    message = "Authentication required"
    def has_permission(self, source, info: Info, **kwargs) -> bool:
        return info.context.current_user_id is not None

class IsAdmin(BasePermission):
    message = "Admin role required"
    async def has_permission(self, source, info: Info, **kwargs) -> bool:
        uid = info.context.current_user_id
        if not uid:
            return False
        user = await info.context.services.user.get_by_id(uid)
        return user and user.role == UserRole.ADMIN

@strawberry.type
class Mutation:
    @strawberry.mutation(permission_classes=[IsAuthenticated])
    async def create_order(self, info: Info, input: CreateOrderInput) -> Order:
        ...

    @strawberry.mutation(permission_classes=[IsAdmin])
    async def delete_user(self, info: Info, id: strawberry.ID) -> bool:
        ...

# BAD — N+1: every user in the list triggers a separate DB query for orders
@strawberry.type
class User:
    @strawberry.field
    async def orders(self) -> List[Order]:
        return await db.orders.find_all(user_id=self.id)  # called once per user!

# GOOD — batched via DataLoader: all users' orders fetched in one query
@strawberry.type
class User:
    @strawberry.field
    async def orders(self, info: Info) -> List[Order]:
        return await info.context.loaders.orders_by_user.load(self.id)

// src/graphql/cost-limit.ts
import { costLimitPlugin } from "@escape.tech/graphql-armor-cost-limit";
import { maxDepthPlugin }  from "@escape.tech/graphql-armor-max-depth";
import { maxAliasesPlugin } from "@escape.tech/graphql-armor-max-aliases";

export const armorPlugins = [
  costLimitPlugin({ maxCost: 1000, objectCost: 2, scalarCost: 1, depthCostFactor: 1.5 }),
  maxDepthPlugin({ n: 8 }),
  maxAliasesPlugin({ n: 15 }),
];
